const body = $('Webhook Onboarding').first().json.body;
const modulos = (body.modulos_activados || []);
const moduloLabels = {
  facturas: '🧾 Facturación CFDI',
  nomina: '👥 Nómina e IMSS',
  cierre_mensual: '📊 Cierre Mensual',
  whatsapp: '📱 Asistente WhatsApp',
  diot: '📋 DIOT Automática'
};
let msg = `🎉 *¡Bienvenido a MYSTIC, ${body.empresa || 'tu empresa'}!*\n\n`;
msg += `✅ RFC registrado: *${body.rfc || 'N/A'}*\n\n`;
msg += `🚀 Módulos activados:\n`;
modulos.forEach(m => {
  msg += `  ${moduloLabels[m] || m}\n`;
});
msg += `\n📱 Puedes preguntarme por WhatsApp cualquier duda fiscal.`;
msg += `\n🌐 Panel: sonoradigitalcorp.com/panel`;
const numero = body.numero_wa || '526622681111';
return [{ json: { mensaje: msg, numero } }];
